import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css"; 

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpError, setOtpError] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [email, setEmail] = useState(null);

  const navigate = useNavigate();

  // Get email from sessionStorage (set during Forgot Password)
  useEffect(() => {
    const storedEmail = sessionStorage.getItem("resetEmail");
    if (!storedEmail) {
      navigate("/forgot-password"); 
    } else {
      setEmail(storedEmail);
    }
  }, [navigate]);

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setOtpError("");
    setOtpMessage("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    if (!/^\d{6}$/.test(otp)) {
      setOtpError("Invalid OTP format. Must be 6 digits.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { email, otp });

      if (response.data.success) {
        setOtpMessage("OTP Verified Successfully!");
        sessionStorage.removeItem("resetEmail"); // Clear stored email
        setTimeout(() => navigate("/reset-password"), 2000);
      } else {
        setOtpError(response.data.message);
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
      console.error("OTP Verification Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResendOtp = async () => {
    if (!email) return;
    setOtpError("");
    setOtpMessage("Resending OTP...");

    try {
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email });
      setOtpMessage(response.data.message);
    } catch (err) {
      setOtpError("Error resending OTP. Try again later.");
      console.error("Resend OTP Error:", err);
    }
  };

  return (
    <div className="verify-otp-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      
      <div className="verify-otp-card">
        <h2>Verify OTP</h2>
        <p>Enter the 6-digit OTP sent to your email</p>

        <form onSubmit={handleOtpSubmit}>
          <div className="input-group">
            <span className="icon">🔒</span>
            <input
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              maxLength="6"
              required
              disabled={isSubmitting}
            />
          </div>

          <button type="submit" className="verify-otp-button" disabled={isSubmitting}>
            {isSubmitting ? "Verifying..." : "Verify OTP"}
          </button>
        </form>

        <div className="message-container">
          {otpMessage && <p className="success-message">{otpMessage}</p>}
          {otpError && <p className="error-message">{otpError}</p>}
        </div>

        <button onClick={handleResendOtp} className="resend-otp-button">
          Resend OTP
        </button>

        <a href="/forgot-password" className="back-link">Back to Forgot Password</a>
      </div>
    </div>
  );
};

export default VerifyOtpPage;
